R = int(input())
notes = [2000, 500, 200, 100, 50, 20, 10, 5, 2, 1]
count = {}
for note in notes:
    if R >= note:
        count[note] = R // note
        R %= note

total = sum(count.values())
print(f"Minimum number of notes = {total}")
for k in notes:
    if k in count:
        print(f"{k} : {count[k]}")
